@startuml
skinparam classAttributeIconSize 0

abstract class Personnage << (A,#BFE7EA) >> {
  void combattre()
  void setArme(ComportementArme)
}

class Troll << (C,#BFE7C6) >>
class Roi << (C,#BFE7C6) >>
class Reine << (C,#BFE7C6) >>
class Chevalier << (C,#BFE7C6) >>

interface ComportementArme << (I,#B9B3E6) >> {
  void utiliserArme()
}

class ComportementPoignard << (C,#BFE7C6) >> {
  void utiliserArme()
}
class ComportementEpee << (C,#BFE7C6) >> {
  void utiliserArme()
}
class ComportementArc << (C,#BFE7C6) >> {
  void utiliserArme()
}

class Aventure << (C,#BFE7C6) >> {
  void main(String)
}

Troll --|> Personnage
Roi --|> Personnage
Reine --|> Personnage
Chevalier --|> Personnage

Personnage "1" --> ComportementArme

ComportementPoignard ..|> ComportementArme
ComportementEpee ..|> ComportementArme
ComportementArc ..|> ComportementArme
@enduml
